# ruff: noqa: E501
"""Build the AIUC-1 standard JSON from scraped data.

This script constructs the complete aiuc/aiuc-1-standard.json file
from data scraped from https://www.aiuc-1.com.
"""

from __future__ import annotations

import json
from datetime import UTC, datetime
from pathlib import Path


def build_aiuc_standard() -> dict:
    """Build the complete AIUC-1 standard data structure."""
    return {
        "standard": "AIUC-1",
        "version": "1.0",
        "url": "https://www.aiuc-1.com",
        "scraped_at": datetime.now(UTC).isoformat(),
        "domains": [
            _domain_a(),
            _domain_b(),
            _domain_c(),
            _domain_d(),
            _domain_e(),
            _domain_f(),
        ],
    }


def _ctrl(
    id: str,
    title: str,
    url: str,
    classification: str,
    type: str,
    frequency: str,
    description: str,
    applicable_capabilities: list[str],
    activities: list[dict],
    keywords: list[str],
    framework_references: dict,
) -> dict:
    return {
        "id": id,
        "title": title,
        "url": f"https://www.aiuc-1.com{url}",
        "classification": classification,
        "type": type,
        "frequency": frequency,
        "description": description,
        "applicable_capabilities": applicable_capabilities,
        "activities": activities,
        "keywords": keywords,
        "framework_references": framework_references,
    }


def _act(id: str, description: str, category: str = "Core", evidence_types: list[str] | None = None) -> dict:
    return {
        "id": id,
        "description": description,
        "category": category,
        "evidence_types": evidence_types or [],
    }


def _refs(
    eu_ai_act: list[str] | None = None,
    iso_42001: list[str] | None = None,
    nist_ai_rmf: list[str] | None = None,
    csa_aicm: list[str] | None = None,
    owasp_llm_top10: list[str] | None = None,
    owasp_aivss: list[str] | None = None,
    mitre_atlas: list[str] | None = None,
) -> dict:
    return {
        "eu_ai_act": eu_ai_act or [],
        "iso_42001": iso_42001 or [],
        "nist_ai_rmf": nist_ai_rmf or [],
        "csa_aicm": csa_aicm or [],
        "owasp_llm_top10": owasp_llm_top10 or [],
        "owasp_aivss": owasp_aivss or [],
        "mitre_atlas": mitre_atlas or [],
    }


