def main() -> None:
    data = build_aiuc_standard()
    output_path = Path(__file__).parent.parent / "aiuc" / "aiuc-1-standard.json"
    with open(output_path, "w") as f:
        json.dump(data, f, indent=2)

    # Count controls and activities
    total_controls = sum(len(d["controls"]) for d in data["domains"])
    total_activities = sum(
        len(c["activities"])
        for d in data["domains"]
        for c in d["controls"]
    )
    print(f"Written {output_path}")
    print(f"  Domains: {len(data['domains'])}")
    print(f"  Controls: {total_controls}")
    print(f"  Activities: {total_activities}")


if __name__ == "__main__":
    main()
